  static description = 'Approve a staged package, publishing it to the npm registry'
  static name = 'approve'
  static usage = ['<stage-id>']
  static params = ['otp', 'registry']
  static positionals = 1

  async exec (args) {
    if (!args[0]) {
      throw this.usageError('Missing required <stage-id>')
